+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track = {
+	base: number;
+	fr: number;
+	auto: boolean;
+};
+
+type Placement = {start: number; end: number};
+
+const tokenizeTracks = (template: string): string[] =>
+	template.match(/minmax\\([^)]*\\)|[^\\s]+/g) ?? [];
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {base: 0, fr: 0, auto: true};
+	}
+
+	if (value.endsWith('fr')) {
+		return {base: 0, fr: Number.parseFloat(value) || 1, auto: false};
+	}
+
+	if (value.startsWith('minmax(') && value.endsWith(')')) {
+		const [minimum, maximum] = value.slice(7, -1).split(',').map(part => part.trim());
+		const base = Number.parseFloat(minimum);
+		if (!Number.isFinite(base) || !maximum) {
+			throw new Error(`Invalid grid track size: ${value}`);
+		}
+
+		if (maximum.endsWith('fr')) {
+			return {
+				base,
+				fr: Number.parseFloat(maximum) || 1,
+				auto: false,
+			};
+		}
+
+		const maximumSize = Number.parseFloat(maximum);
+		if (!Number.isFinite(maximumSize)) {
+			throw new Error(`Invalid grid track size: ${value}`);
+		}
+
+		return {base: Math.max(base, maximumSize), fr: 0, auto: false};
+	}
+
+	const size = Number.parseFloat(value);
+	if (!Number.isFinite(size)) {
+		throw new Error(`Invalid grid track size: ${value}`);
+	}
+
+	return {base: size, fr: 0, auto: false};
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	template ? tokenizeTracks(template).map(parseTrack) : [];
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value !== 'string') {
+		return;
+	}
+
+	const parts = value.split('/').map(part => Number.parseInt(part.trim(), 10));
+	if (parts.length !== 2 || parts.some(part => !Number.isInteger(part)) || parts[1] <= parts[0]) {
+		throw new Error(`Invalid grid placement: ${value}`);
+	}
+
+	return {start: parts[0] - 1, end: parts[1] - 1};
+};
+
+const sum = (values: number[], start: number, end: number): number =>
+	values.slice(start, end).reduce((total, value) => total + value, 0);
+
+const trackOffsets = (sizes: number[], gap: number): number[] => {
+	const offsets: number[] = [];
+	let offset = 0;
+	for (const size of sizes) {
+		offsets.push(offset);
+		offset += size + gap;
+	}
+
+	return offsets;
+};
+
+const layoutGrid = (element: DOMElement): void => {
+	const yogaNode = element.yogaNode;
+	if (!yogaNode || element.style.display !== 'grid') {
+		return;
+	}
+
+	const columns = parseTracks(element.style.gridTemplateColumns);
+	if (columns.length === 0) {
+		throw new Error('Grid containers require gridTemplateColumns');
+	}
+
+	const children = element.childNodes.filter(
+		(child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode),
+	);
+	const columnGap = element.style.columnGap ?? element.style.gap ?? 0;
+	const rowGap = element.style.rowGap ?? element.style.gap ?? 0;
+	const paddingX = yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + yogaNode.getComputedPadding(Yoga.EDGE_RIGHT);
+	const paddingY = yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM);
+	const availableWidth = Math.max(0, yogaNode.getComputedWidth() - paddingX);
+
+	const placements: Array<{element: DOMElement; column: Placement; row: Placement}> = [];
+	const occupied = new Set<string>();
+	let cursorColumn = 0;
+	let cursorRow = 0;
+	for (const child of children) {
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		let resolvedColumn = column;
+		let resolvedRow = row;
+
+		if (!resolvedColumn || !resolvedRow) {
+			while (occupied.has(`${cursorRow}:${cursorColumn}`)) {
+				cursorColumn++;
+				if (cursorColumn === columns.length) {
+					cursorColumn = 0;
+					cursorRow++;
+				}
+			}
+
+			resolvedColumn ??= {start: cursorColumn, end: cursorColumn + 1};
+			resolvedRow ??= {start: cursorRow, end: cursorRow + 1};
+		}
+
+		for (let rowIndex = resolvedRow.start; rowIndex < resolvedRow.end; rowIndex++) {
+			for (let columnIndex = resolvedColumn.start; columnIndex < resolvedColumn.end; columnIndex++) {
+				occupied.add(`${rowIndex}:${columnIndex}`);
+			}
+		}
+
+		placements.push({element: child, column: resolvedColumn, row: resolvedRow});
+	}
+
+	for (const placement of placements) {
+		if (placement.column.end > columns.length || placement.column.start < 0 || placement.row.start < 0) {
+			throw new Error('Grid placement is outside the defined grid');
+		}
+		if (placement.column.end - placement.column.start !== 1) {
+			continue;
+		}
+
+		const track = columns[placement.column.start];
+		if (track.auto) {
+			placement.element.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+			track.base = Math.max(track.base, placement.element.yogaNode!.getComputedWidth());
+		}
+	}
+
+	const columnBase = columns.reduce((total, track) => total + track.base, 0);
+	const columnFr = columns.reduce((total, track) => total + track.fr, 0);
+	const columnRemaining = Math.max(0, availableWidth - columnBase - columnGap * (columns.length - 1));
+	const columnSizes = columns.map(track => track.base + (columnFr ? columnRemaining * track.fr / columnFr : 0));
+	const columnOffsets = trackOffsets(columnSizes, columnGap);
+
+	const rows = parseTracks(element.style.gridTemplateRows);
+	const highestRow = placements.reduce((highest, placement) => Math.max(highest, placement.row.end), 0);
+	while (rows.length < highestRow) {
+		rows.push({base: 0, fr: 0, auto: true});
+	}
+
+	for (const placement of placements) {
+		const width = sum(columnSizes, placement.column.start, placement.column.end) + columnGap * (placement.column.end - placement.column.start - 1);
+		placement.element.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		placement.element.yogaNode!.setWidth(width);
+		placement.element.yogaNode!.calculateLayout(width, undefined, Yoga.DIRECTION_LTR);
+		if (placement.row.end - placement.row.start === 1 && rows[placement.row.start].auto) {
+			rows[placement.row.start].base = Math.max(rows[placement.row.start].base, placement.element.yogaNode!.getComputedHeight());
+		}
+	}
+
+	const availableHeight = Math.max(0, yogaNode.getComputedHeight() - paddingY);
+	const rowBase = rows.reduce((total, track) => total + track.base, 0);
+	const rowFr = rows.reduce((total, track) => total + track.fr, 0);
+	const rowRemaining = Math.max(0, availableHeight - rowBase - rowGap * (rows.length - 1));
+	const rowSizes = rows.map(track => track.base + (rowFr ? rowRemaining * track.fr / rowFr : 0));
+	const rowOffsets = trackOffsets(rowSizes, rowGap);
+
+	if (element.style.height === undefined) {
+		yogaNode.setHeight(rowSizes.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rows.length - 1) + paddingY);
+	}
+
+	for (const placement of placements) {
+		const childNode = placement.element.yogaNode!;
+		const width = sum(columnSizes, placement.column.start, placement.column.end) + columnGap * (placement.column.end - placement.column.start - 1);
+		const height = sum(rowSizes, placement.row.start, placement.row.end) + rowGap * (placement.row.end - placement.row.start - 1);
+		childNode.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column.start]);
+		childNode.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row.start]);
+		childNode.setWidth(width);
+		childNode.setHeight(height);
+	}
+};
+
+export const layoutGrids = (element: DOMElement): void => {
+	for (const child of element.childNodes) {
+		if (child.nodeName !== '#text') {
+			layoutGrids(child);
+			layoutGrids(child);
+		}
+	}
+
+	layoutGrid(element);
+};
